import React, { useEffect, useState } from 'react';
import API from '../api/axios';

export default function Properties() {
  const [properties, setProperties] = useState([]);
  const [showForm, setShowForm] = useState(false);
  const [filters, setFilters] = useState({ type:'', status:'' });
  const [form, setForm] = useState({ title:'', type:'residential', price:'', size_sqft:'', location:'', status:'available' });

  const fetchProperties = () => {
    const params = new URLSearchParams(filters).toString();
    API.get(`/properties?${params}`).then(r => setProperties(r.data));
  };

  useEffect(() => { fetchProperties(); }, [filters]);

  const handleSubmit = async (e) => {
    e.preventDefault();
    await API.post('/properties', form);
    setShowForm(false);
    setForm({ title:'', type:'residential', price:'', size_sqft:'', location:'', status:'available' });
    fetchProperties();
  };

  const deleteProperty = async (id) => {
    if (window.confirm('Delete this property?')) {
      await API.delete(`/properties/${id}`);
      fetchProperties();
    }
  };

  const STATUS_COLOR = { available:'#10b981', sold:'#ef4444', rented:'#3b82f6' };

  return (
    <div style={styles.page}>
      <div style={styles.header}>
        <h1 style={styles.title}>🏢 Properties</h1>
        <button onClick={() => setShowForm(!showForm)} style={styles.addBtn}>+ Add Property</button>
      </div>

      {/* Filters */}
      <div style={styles.filterRow}>
        <select style={styles.filterSelect} value={filters.type} onChange={e => setFilters({...filters, type:e.target.value})}>
          <option value="">All Types</option>
          <option value="residential">Residential</option>
          <option value="commercial">Commercial</option>
        </select>
        <select style={styles.filterSelect} value={filters.status} onChange={e => setFilters({...filters, status:e.target.value})}>
          <option value="">All Status</option>
          <option value="available">Available</option>
          <option value="sold">Sold</option>
          <option value="rented">Rented</option>
        </select>
      </div>

      {/* Add Form */}
      {showForm && (
        <div style={styles.formBox}>
          <h3 style={{ marginBottom:'16px' }}>New Property</h3>
          <form onSubmit={handleSubmit} style={styles.formGrid}>
            <input placeholder="Title *" required style={styles.input} value={form.title} onChange={e => setForm({...form, title:e.target.value})} />
            <input placeholder="Location" style={styles.input} value={form.location} onChange={e => setForm({...form, location:e.target.value})} />
            <input placeholder="Price (₹)" type="number" style={styles.input} value={form.price} onChange={e => setForm({...form, price:e.target.value})} />
            <input placeholder="Size (sqft)" type="number" style={styles.input} value={form.size_sqft} onChange={e => setForm({...form, size_sqft:e.target.value})} />
            <select style={styles.input} value={form.type} onChange={e => setForm({...form, type:e.target.value})}>
              <option value="residential">Residential</option>
              <option value="commercial">Commercial</option>
            </select>
            <select style={styles.input} value={form.status} onChange={e => setForm({...form, status:e.target.value})}>
              <option value="available">Available</option>
              <option value="sold">Sold</option>
              <option value="rented">Rented</option>
            </select>
            <div style={{ gridColumn:'1/-1', display:'flex', gap:'10px' }}>
              <button type="submit" style={styles.addBtn}>Save Property</button>
              <button type="button" onClick={() => setShowForm(false)} style={styles.cancelBtn}>Cancel</button>
            </div>
          </form>
        </div>
      )}

      {/* Property Cards */}
      <div style={styles.grid}>
        {properties.map(p => (
          <div key={p.id} style={styles.card}>
            <div style={styles.cardImg}>🏠</div>
            <div style={styles.cardBody}>
              <div style={{ display:'flex', justifyContent:'space-between', alignItems:'flex-start' }}>
                <h3 style={styles.cardTitle}>{p.title}</h3>
                <span style={{ ...styles.statusBadge, background: STATUS_COLOR[p.status] + '20', color: STATUS_COLOR[p.status] }}>
                  {p.status}
                </span>
              </div>
              <div style={styles.cardMeta}>📍 {p.location || 'Location not set'}</div>
              <div style={styles.cardMeta}>💰 ₹{Number(p.price || 0).toLocaleString()}</div>
              <div style={styles.cardMeta}>📐 {p.size_sqft || '—'} sqft • {p.type}</div>
              <div style={{ display:'flex', justifyContent:'flex-end', marginTop:'12px' }}>
                <button onClick={() => deleteProperty(p.id)} style={styles.deleteBtn}>🗑️ Delete</button>
              </div>
            </div>
          </div>
        ))}
      </div>
      {properties.length === 0 && <div style={styles.empty}>No properties found.</div>}
    </div>
  );
}

const styles = {
  page: { padding:'24px' },
  header: { display:'flex', justifyContent:'space-between', alignItems:'center', marginBottom:'20px' },
  title: { fontSize:'22px', fontWeight:'700', color:'#1e293b' },
  addBtn: { padding:'10px 20px', background:'#3b82f6', color:'#fff', border:'none', borderRadius:'8px', cursor:'pointer', fontWeight:'600' },
  cancelBtn: { padding:'10px 20px', background:'#e2e8f0', color:'#475569', border:'none', borderRadius:'8px', cursor:'pointer' },
  filterRow: { display:'flex', gap:'12px', marginBottom:'20px' },
  filterSelect: { padding:'8px 12px', border:'1px solid #e2e8f0', borderRadius:'8px', fontSize:'14px', background:'#fff' },
  formBox: { background:'#fff', padding:'20px', borderRadius:'10px', marginBottom:'20px', boxShadow:'0 1px 8px rgba(0,0,0,0.08)' },
  formGrid: { display:'grid', gridTemplateColumns:'1fr 1fr', gap:'12px' },
  input: { padding:'10px 12px', border:'1px solid #e2e8f0', borderRadius:'8px', fontSize:'14px', outline:'none' },
  grid: { display:'grid', gridTemplateColumns:'repeat(3, 1fr)', gap:'16px' },
  card: { background:'#fff', borderRadius:'10px', boxShadow:'0 1px 8px rgba(0,0,0,0.08)', overflow:'hidden' },
  cardImg: { background:'#f1f5f9', height:'100px', display:'flex', alignItems:'center', justifyContent:'center', fontSize:'40px' },
  cardBody: { padding:'16px' },
  cardTitle: { fontSize:'15px', fontWeight:'600', color:'#1e293b', marginBottom:'8px' },
  cardMeta: { fontSize:'13px', color:'#64748b', marginBottom:'4px' },
  statusBadge: { padding:'3px 10px', borderRadius:'20px', fontSize:'11px', fontWeight:'600' },
  deleteBtn: { padding:'6px 12px', background:'#fee2e2', color:'#dc2626', border:'none', borderRadius:'6px', cursor:'pointer', fontSize:'12px' },
  empty: { padding:'60px', textAlign:'center', color:'#94a3b8', background:'#fff', borderRadius:'10px' }
};
